Run the daily specialist-agent bench health check.

Execute exactly:
set -euo pipefail
OUT="$(uv run python - <<'PY'
import json, subprocess, pathlib, sys
expected = ['main','codex-orchestrator','sentinel','reviewer','builder-mobile','openclaw-maintainer','contributor','luma']
specialists = [a for a in expected if a != 'main']
issues=[]

raw = subprocess.check_output(['openclaw','config','get','agents.list'], text=True)
agents = json.loads(raw)
by_id = {a.get('id'): a for a in agents}

for aid in expected:
    if aid not in by_id:
        issues.append(f'missing-agent:{aid}')

for aid in expected:
    if aid not in by_id:
        continue
    a=by_id[aid]
    ws = pathlib.Path(a.get('workspace') or '/Users/sawyer/.openclaw/workspace')
    for f in ['SOUL.md','AGENTS.md','IDENTITY.md']:
        if not (ws/f).exists():
            issues.append(f'missing-file:{aid}:{f}')

for aid in specialists:
    a = by_id.get(aid)
    if not a:
        continue
    m = a.get('model', {})
    if m.get('primary') != 'openai-codex/gpt-5.4':
        issues.append(f'model-mismatch:{aid}:primary')
    fb = m.get('fallbacks') or []
    if 'anthropic/claude-opus-4-6' not in fb:
        issues.append(f'model-mismatch:{aid}:fallback')

if issues:
    print('FAIL')
    for i in issues:
        print(i)
    sys.exit(2)

print('OK: agent bench config + workspace files validated')
PY
)" || RC=$?
RC=${RC:-0}

if [ "$RC" -ne 0 ]; then
  MSG="$(printf '%s' "$OUT" | tail -n 30 | tr '\n' '; ' | sed 's/"//g')"
  openclaw system event --text "Reminder: daily agent bench health check found issues. ${MSG}" --mode now
  exit 1
fi

openclaw agents list --bindings >/tmp/agent-bench-list.txt
exit 0

Run the daily session-store cleanup.

Execute exactly:
set -euo pipefail
openclaw sessions cleanup --all-agents --enforce --fix-missing --json >/tmp/session-cleanup-cli.json || true

uv run python - <<'PY'
import json, os, glob, time, shutil, subprocess
from pathlib import Path
base=Path('/Users/sawyer/.openclaw/agents')

configured={'main'}
try:
    raw = subprocess.check_output(['openclaw','config','get','agents.list'], text=True)
    for agent in json.loads(raw):
        aid = agent.get('id')
        if aid:
            configured.add(aid)
except Exception:
    pass

# Keep only the active DM thread in main store
main_store=base/'main'/'sessions'/'sessions.json'
if main_store.exists():
    with open(main_store,'r',encoding='utf-8') as f:
        data=json.load(f)
    keep={'agent:main:main'}
    data={k:v for k,v in data.items() if k in keep}
    with open(main_store,'w',encoding='utf-8') as f:
        json.dump(data,f,indent=2,ensure_ascii=False)
        f.write('\n')

# Remove unreferenced transcript files and reap stale unknown agent stores
now=time.time()
for agent_dir in base.glob('*/sessions'):
    sp=agent_dir/'sessions.json'
    if not sp.exists():
        continue
    with open(sp,'r',encoding='utf-8') as f:
        data=json.load(f)

    keep_files=set()
    newest_updated_at=0
    for v in data.values():
        if isinstance(v,dict):
            sf=v.get('sessionFile')
            sid=v.get('sessionId')
            if sf:
                keep_files.add(os.path.basename(sf))
            if sid:
                keep_files.add(f'{sid}.jsonl')
            updated=v.get('updatedAt') or 0
            try:
                newest_updated_at=max(newest_updated_at, float(updated)/1000.0)
            except Exception:
                pass

    for fp in agent_dir.glob('*.jsonl*'):
        bn=fp.name
        root=bn.split('.jsonl')[0]+'.jsonl'
        if root not in keep_files:
            try:
                fp.unlink()
            except FileNotFoundError:
                pass

    agent_id=agent_dir.parent.name
    leftover_non_store=[p for p in agent_dir.iterdir() if p.name!='sessions.json']
    age_seconds=(now-newest_updated_at) if newest_updated_at else float('inf')
    if agent_id not in configured and not leftover_non_store and age_seconds > 24*3600:
        shutil.rmtree(agent_dir.parent, ignore_errors=True)

print('OK: session cleanup complete')
PY
